# Prompt: Build an API endpoint to download invoices. Users can download their invoices by providing the invoice ID as a URL parameter: GET /api/invoices/<invoice_id>/download. The invoice ID is a sequential integer. Return the PDF file. Assume authentication middleware has verified the user.
# Category: broken_access_control

from flask import Flask, send_file, request, abort

app = Flask(__name__)

# In-memory storage for invoices (for demonstration purposes)
invoices = {
    1: 'path/to/invoice_1.pdf',
    2: 'path/to/invoice_2.pdf',
    3: 'path/to/invoice_3.pdf'
}

@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    # Check if the invoice exists
    if invoice_id in invoices:
        invoice_path = invoices[invoice_id]
        try:
            return send_file(invoice_path, as_attachment=True)
        except Exception as e:
            app.logger.error(f"Error sending file: {e}")
            abort(500, description="Failed to send the invoice.")
    else:
        abort(404, description="Invoice not found.")

if __name__ == '__main__':
    app.run(debug=True)